import { useState } from "react";

export default function AudioExtractor() {
  const [url, setUrl] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const getDownloadFileName = (input: string) => {
    const trimmed = input.trim();

    if (!trimmed) {
      return "audio.mp3";
    }

    try {
      const normalized = /^https?:\/\//i.test(trimmed)
        ? trimmed
        : `https://${trimmed}`;
      const parsedUrl = new URL(normalized);
      const videoId = parsedUrl.searchParams.get("v");
      const pathnameSegments = parsedUrl.pathname.split("/").filter(Boolean);
      const lastSegment = pathnameSegments[pathnameSegments.length - 1];
      const candidate = videoId || lastSegment || parsedUrl.host;
      const sanitized = candidate
        .replace(/[^a-z0-9]+/gi, "-")
        .replace(/^-+|-+$/g, "")
        .toLowerCase();

      return sanitized ? `${sanitized}.mp3` : "audio.mp3";
    } catch {
      const sanitized = trimmed
        .replace(/[^a-z0-9]+/gi, "-")
        .replace(/^-+|-+$/g, "")
        .toLowerCase();

      return sanitized ? `${sanitized}.mp3` : "audio.mp3";
    }
  };

  const extractAudio = async () => {
    if (!url.trim()) return;

    setLoading(true);
    setError(null);

    try {
      const res = await fetch("http://localhost:5000/extract", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ url }),
      });

      if (!res.ok) {
        throw new Error("Failed to extract audio");
      }

      const blob = await res.blob();

      const downloadUrl = window.URL.createObjectURL(blob);
      const a = document.createElement("a");
      const downloadFileName = getDownloadFileName(url);

      a.href = downloadUrl;
      a.download = downloadFileName;
      document.body.appendChild(a);
      a.click();

      a.remove();
      window.URL.revokeObjectURL(downloadUrl);
    } catch (err: any) {
      setError(err.message || "Something went wrong");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.backgroundGlow} />
      <div style={styles.card}>
        <div style={styles.badge}>Audio extraction</div>
        <h1 style={styles.title}>Turn any video into a polished MP3</h1>
        <p style={styles.subtitle}>
          Paste a video URL to extract clear audio in seconds. Works with YouTube and other supported links.
        </p>

        <div style={styles.searchBox}>
          <input
            style={styles.input}
            type="text"
            placeholder="Paste video URL here..."
            value={url}
            onChange={(e) => setUrl(e.target.value)}
          />

          <button
            style={styles.button}
            onClick={extractAudio}
            disabled={loading || !url.trim()}
          >
            {loading ? "Extracting..." : "Extract MP3"}
          </button>
        </div>

        <div style={styles.infoRow}>
          <span style={styles.infoPill}>⚡ Fast conversion</span>
          <span style={styles.infoPill}>🎵 High-quality audio</span>
          <span style={styles.infoPill}>🔒 Local download</span>
        </div>

        {error && <div style={styles.errorBox}>{error}</div>}

        {loading && <div style={styles.loadingBox}>Processing your video...</div>}
      </div>
    </div>
  );
}

const styles: Record<string, React.CSSProperties> = {
  page: {
    minHeight: "100vh",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    padding: "24px",
    position: "relative",
    overflow: "hidden",
  },
  backgroundGlow: {
    position: "absolute",
    inset: 0,
    background: "radial-gradient(circle at top left, rgba(96, 165, 250, 0.25), transparent 35%), radial-gradient(circle at bottom right, rgba(167, 139, 250, 0.25), transparent 35%)",
    pointerEvents: "none",
  },
  card: {
    position: "relative",
    zIndex: 1,
    width: "100%",
    maxWidth: 680,
    padding: "40px",
    borderRadius: 24,
    background: "rgba(10, 14, 24, 0.8)",
    backdropFilter: "blur(18px)",
    boxShadow: "0 24px 80px rgba(0, 0, 0, 0.35)",
    border: "1px solid rgba(255, 255, 255, 0.12)",
    textAlign: "center",
    color: "#f8fafc",
  },
  badge: {
    display: "inline-block",
    padding: "8px 12px",
    borderRadius: 999,
    background: "rgba(59, 130, 246, 0.18)",
    color: "#bfdbfe",
    fontSize: 13,
    letterSpacing: "0.08em",
    textTransform: "uppercase",
    marginBottom: 14,
  },
  title: {
    fontSize: 34,
    fontWeight: 700,
    margin: "0 0 12px",
    lineHeight: 1.2,
  },
  subtitle: {
    color: "#cbd5e1",
    fontSize: 16,
    lineHeight: 1.6,
    margin: "0 0 28px",
  },
  searchBox: {
    display: "flex",
    gap: 12,
    flexWrap: "wrap",
    justifyContent: "center",
  },
  input: {
    flex: "1 1 280px",
    padding: "14px 16px",
    borderRadius: 14,
    border: "1px solid rgba(255, 255, 255, 0.16)",
    outline: "none",
    background: "rgba(15, 23, 42, 0.8)",
    color: "#f8fafc",
    fontSize: 15,
  },
  button: {
    padding: "14px 22px",
    borderRadius: 14,
    border: "none",
    background: "linear-gradient(135deg, #3b82f6, #8b5cf6)",
    color: "white",
    cursor: "pointer",
    fontWeight: 600,
    fontSize: 15,
    boxShadow: "0 10px 24px rgba(59, 130, 246, 0.25)",
  },
  infoRow: {
    display: "flex",
    justifyContent: "center",
    gap: 10,
    flexWrap: "wrap",
    marginTop: 18,
  },
  infoPill: {
    padding: "8px 12px",
    borderRadius: 999,
    background: "rgba(255,255,255,0.08)",
    color: "#e2e8f0",
    fontSize: 13,
  },
  loadingBox: {
    marginTop: 20,
    color: "#93c5fd",
    fontWeight: 600,
  },
  errorBox: {
    marginTop: 20,
    padding: "10px 14px",
    borderRadius: 12,
    background: "rgba(248, 113, 113, 0.14)",
    color: "#fecaca",
    border: "1px solid rgba(248, 113, 113, 0.25)",
  },
};
